1	// description:
2	// 1. rvv_backend_dispatch_structure_hazard sub-module is used to check structure hazard
3	//    for uop(s)
4	//
5	
6	`ifndef HDL_VERILOG_RVV_DESIGN_RVV_SVH
7	`include "rvv_backend.svh"
8	`endif
9	`ifndef RVV_DISPATCH__SVH
10	`include "rvv_backend_dispatch.svh"
11	`endif
12	
13	module rvv_backend_dispatch_structure_hazard
14	(
15	    rd_index,
16	    arch_hazard,
17	    strct_uop
18	);
19	
20	//---port definition--------------------------------------------------
21	    output logic [`NUM_DP_VRF-1:0][`REGFILE_INDEX_WIDTH-1:0] rd_index;
22	    output ARCH_HAZARD_t                                     arch_hazard;
23	    input  STRCT_UOP_t [`NUM_DP_UOP-1:0]                     strct_uop;
24	//---internal signal definition---------------------------------------
25	//---code start-------------------------------------------------------
26	//determine rd_index for VRF read ports
27	
28	    generate
29	`ifdef DISPATCH3
30	      // 6 read ports of VRF
31	      // rd0 : uop0.vs1 or uop2 
32	      // rd1 : uop0.vs2 or uop2
33	      // rd2 : uop0.vs3 or uop2
34	      // rd3 : uop1.vs1 or uop2
35	      // rd4 : uop1.vs2 or uop2
36	      // rd5 : uop1.vs3 or uop2
37	      // check structure hazard for uop2
38	      always_comb begin
39	        rd_index[0] = strct_uop[0].vs1_index;
40	        rd_index[1] = strct_uop[0].vs2_index;
41	        rd_index[2] = strct_uop[0].vd_index;
42	        rd_index[3] = strct_uop[1].vs1_index;
43	        rd_index[4] = strct_uop[1].vs2_index;
44	        rd_index[5] = strct_uop[1].vd_index;
45	        
46	        arch_hazard.vr_limit = 1'b1;
47	
48	        case(strct_uop[2].uop_class)
49	          XXX: begin
50	            arch_hazard.vr_limit = 'b0;
51	          end
52	
53	          XXV,
54	          XVX,
55	          VXX: begin
56	            case(strct_uop[0].uop_class)
57	              XXV,
58	              XVV: begin
59	                case(1'b1)
60	                  strct_uop[2].vs3_valid: rd_index[2] = strct_uop[2].vd_index;
61	                  strct_uop[2].vs2_valid: rd_index[2] = strct_uop[2].vs2_index;
62	                  default:                rd_index[2] = strct_uop[2].vs1_index;
63	                endcase
64	                arch_hazard.vr_limit = 'b0;
65	              end
66	
67	              XXX,
68	              XVX,
69	              VXX,
70	              VVX: begin
71	                case(1'b1)
72	                  strct_uop[2].vs3_valid: rd_index[0] = strct_uop[2].vd_index;
73	                  strct_uop[2].vs2_valid: rd_index[0] = strct_uop[2].vs2_index;
74	                  default:                rd_index[0] = strct_uop[2].vs1_index;
75	                endcase
76	                arch_hazard.vr_limit = 'b0;
77	              end
78	
79	              VVV: begin 
80	                case(strct_uop[1].uop_class)
81	                  XXV,
82	                  XVV: begin
83	                    case(1'b1)
84	                      strct_uop[2].vs3_valid: rd_index[5] = strct_uop[2].vd_index;
85	                      strct_uop[2].vs2_valid: rd_index[5] = strct_uop[2].vs2_index;
86	                      default:                rd_index[5] = strct_uop[2].vs1_index;
87	                    endcase
88	                    arch_hazard.vr_limit = 'b0;
89	                  end
90	
91	                  XXX,
92	                  XVX,
93	                  VXX,
94	                  VVX: begin
95	                    case(1'b1)
96	                      strct_uop[2].vs3_valid: rd_index[3] = strct_uop[2].vd_index;
97	                      strct_uop[2].vs2_valid: rd_index[3] = strct_uop[2].vs2_index;
98	                      default:                rd_index[3] = strct_uop[2].vs1_index;
99	                    endcase
100	                    arch_hazard.vr_limit = 'b0;
101	                  end
102	
103	                  //VVV: arch_hazard.vr_limit = 'b1;
104	                endcase
105	              end
106	            endcase
107	          end
108	          
109	          XVV,
110	          VVX: begin
111	            case(strct_uop[0].uop_class)
112	              XXX,
113	              VXX: begin
114	                rd_index[0] = strct_uop[2].vs1_valid ? strct_uop[2].vs1_index : 
115	                                                       strct_uop[2].vd_index ;
116	                rd_index[1] = strct_uop[2].vs2_index;
117	                arch_hazard.vr_limit = 'b0;
118	              end
119	
120	              XXV: begin
121	                rd_index[2] = strct_uop[2].vs1_valid ? strct_uop[2].vs1_index : 
122	                                                       strct_uop[2].vd_index ;
123	                rd_index[1] = strct_uop[2].vs2_index ;
124	                arch_hazard.vr_limit = 'b0;
125	              end
126	
