1	`ifndef HDL_VERILOG_RVV_DESIGN_RVV_SVH
2	`define HDL_VERILOG_RVV_DESIGN_RVV_SVH
3	
4	`ifndef HDL_VERILOG_RVV_DESIGN_RVV_DEFINE_SVH
5	`include "rvv_backend_define.svh"
6	`endif  // not defined HDL_VERILOG_RVV_DESIGN_RVV_DEFINE_SVH
7	
8	`ifndef HDL_VERILOG_RVV_OPCODE_SVH
9	`include "rvv_backend_opcode.svh"
10	`endif // HDL_VERILOG_RVV_OPCODE_SVH
11	
12	//
13	// IF stage, RVS send instruction package to Command Queue
14	//
15	
16	// Enum type for SEW. See Table 2 in:
17	// https://github.com/riscv/riscv-v-spec/blob/master/v-spec.adoc#341-vector-selected-element-width-vsew20
18	typedef enum logic [2:0] {
19	  SEW8=0,
20	  SEW16=1,
21	  SEW32=2,
22	  SEW64=3
23	} RVVSEW;
24	
25	// Enum type for LMUL. See:
26	// https://github.com/riscv/riscv-v-spec/blob/master/v-spec.adoc#vector-instruction-formats
27	typedef enum logic [2:0] {
28	  LMUL1=0,
29	  LMUL2=1,
30	  LMUL4=2,
31	  LMUL8=3,
32	  LMULRESERVED=4,
33	  LMUL1_8=5, // 1/8
34	  LMUL1_4=6, // 1/4
35	  LMUL1_2=7  // 1/2
36	} RVVLMUL;
37	
38	// Enum type for vtype.vxrm: rounding mode
39	typedef enum logic [1:0] {
40	  RNU = 0,
41	  RNE = 1,
42	  RDN = 2,
43	  ROD = 3
44	} RVVXRM;
45	
46	// Floating-point Rounding Mode
47	typedef enum logic [2:0] {
48	  FRNE=0,
49	  FRTZ=1,
50	  FRDN=2,
51	  FRUP=3,
52	  FRMM=4,
53	  FR_UNREACH_5=5,
54	  FR_UNREACH_6=6,
55	  FRDYN=7
56	} RVFRM;
57	
58	// Floating-point Exception
59	typedef struct packed {
60	  logic nv;   
61	  logic dz; 
62	  logic of;   
63	  logic uf;   
64	  logic nx;   
65	} RVFEXP_t;
66	
67	// The architectural configuration state of the RVV core.
68	typedef struct packed {
69	  logic                         vill; // This configuration is illegal
70	  logic [`VL_WIDTH-1:0]         vl;       // Max 128, need one extra bit
71	  logic [`VSTART_WIDTH-1:0]     vstart;
72	  logic [`VTYPE_VMA_WIDTH-1:0]  ma;        // 0:inactive element undisturbed, 1:inactive element agnostic
73	  logic [`VTYPE_VTA_WIDTH-1:0]  ta;        // 0:tail undisturbed, 1:tail agnostic
74	  RVVXRM                        xrm;       
75	  logic [`VCSR_VXSAT_WIDTH-1:0] xsat;   // rvv dont need this bit, but output this to rvs
76	`ifdef ZVE32F_ON
77	  RVFRM                         frm;
78	`endif
79	  RVVSEW                        sew;
80	  RVVLMUL                       lmul;
81	  RVVLMUL                       lmul_orig;
82	} RVVConfigState;
83	
84	// Enum to encode the major opcode of the instruction. See "Section 5. Vector
85	// Instruction Formats" of the RVV 1.0 spec.
86	typedef enum logic [1:0] {
87	  LOAD=0,
88	  STORE=1,
89	  RVV=2
90	} RVVOpCode;
91	
92	// A decoded instruction forwarded to the RVVCore from the scalar core.
93	typedef struct packed {
94	  logic [`PC_WIDTH-1:0] pc;
95	  RVVOpCode             opcode;   // effectively bits [6:0] from instruction
96	  logic [24:0]          bits;     // bits [31:7] from instruction
97	} RVVInstruction;
98	
99	// An command internal to the RVVCore. The immediate value of this command has
100	// been read from the scalar register file if necessary. It also contains
101	// additional data to track configuration register state (ie: SEW, LMUL, etc).
102	typedef struct packed {
103	`ifdef TB_SUPPORT
104	  logic [`PC_WIDTH-1:0] inst_pc;
105	`endif
106	  RVVOpCode             opcode;
107	  logic [24:0]          bits;
108	  logic [31:0]          rs1;
109	  RVVConfigState        arch_state;
110	} RVVCmd;
111	
112	//
113	// DE stage, Command Queue to Uops Queue
114	//
115	// Effective MUL enum
116	typedef enum logic [3:0] {
117	  EMUL1=0,
118	  EMUL2=1,
119	  EMUL4=2,
120	  EMUL8=3,
