              push[4] = uq_ready[4];
              uop[4]  = de_uop[2][2];
            end
            13'b?1_011_??01_???0: begin
              push[4] = uq_ready[4];
              uop[4]  = de_uop[3][0];
            end
            13'b11_?01_??01_???0: begin
              push[4] = uq_ready[4];
              uop[4]  = de_uop[3][1];
            end
            default: begin 
              push[4] = 'b0;
              uop[4]  = de_uop[0][4];
            end
          endcase
        end
      end // NUM_DE_UOP==5

      if(`NUM_DE_UOP>=3'd6) begin : gen_push5_uop5
        always_comb begin
          casez({de_uop_valid[3][2:0],de_uop_valid[2][3:0],de_uop_valid[1][4:0],de_uop_valid[0][5:1]})
            17'b???_????_?????_11111: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[0][5];
            end
            17'b???_????_????1_01111: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[1][0];
            end
            17'b???_????_???11_?0111: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[1][1];
            end
            17'b???_???1_???01_?0111: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][0];
            end
            17'b???_????_??111_??011: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[1][2];
            end
            17'b???_???1_??011_??011: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][0];
            end
            17'b???_??11_???01_??011: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][1];
            end
            17'b??1_??01_???01_??011: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][0];
            end
            17'b???_????_?1111_???01: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[1][3];
            end
            17'b???_???1_?0111_???01: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][0];
            end
            17'b???_??11_??011_???01: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][1];
            end
            17'b??1_??01_??011_???01: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][0];
            end
            17'b???_?111_???01_???01: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][2];
            end
            17'b??1_?011_???01_???01: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][0];
            end
            17'b?11_??01_???01_???01: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][1];
            end
            17'b???_????_11111_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[1][4];
            end
            17'b???_???1_01111_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][0];
            end
            17'b???_??11_?0111_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][1];
            end
            17'b??1_??01_?0111_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][0];
            end
            17'b???_?111_??011_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][2];
            end
            17'b??1_?011_??011_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][0];
            end
            17'b?11_??01_??011_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][1];
            end
            17'b???_1111_???01_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[2][3];
            end
            17'b??1_0111_???01_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][0];
            end
            17'b?11_?011_???01_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][1];
            end
            17'b111_??01_???01_????0: begin
              push[5] = uq_ready[5];
              uop[5]  = de_uop[3][2];
            end
            default: begin 
              push[5] = 'b0;
              uop[5]  = de_uop[0][5];
            end
          endcase
        end
      end // NUM_DE_UOP==6 
    end // NUM_DE_INST==3

    // calculate pop siganl for LCQ
    for(j=0;j<`NUM_DE_UOP;j++) begin : gen_last_uop
      assign last_uop[j] = push[j]&uop[j].last_uop_valid;
    end
  endgenerate

  always_comb begin
    pop = 'b0;
    i   = 0;

    for(int k=0;k<`NUM_DE_UOP;k++) begin
      if (i < `NUM_DE_INST) begin
        if (last_uop[k]) begin
          pop[i] = 1'b1;
          i      = i + 1;
        end
      end
    end
  end

  // uop index remain
  always_comb begin
    uop_index_din = 'b0;

    for(int k=0;k<`NUM_DE_UOP;k++) begin
      if(push[k])
        uop_index_din = uop[k].last_uop_valid ? 'b0 : uop[k].uop_index + (`UOP_INDEX_WIDTH)'('d1);
    end
  end

  assign uop_index_en = |push;

  cdffr 
  #(
    .T         (logic[`UOP_INDEX_WIDTH-1:0])
  )
  uop_index_cdffr
  ( 
    .clk       (clk), 
    .rst_n     (rst_n), 
    .c         (trap_flush_rvv), 
    .e         (uop_index_en), 
    .d         (uop_index_din),
    .q         (uop_index_remain)
  ); 

endmodule

`ifndef HDL_VERILOG_RVV_DESIGN_RVV_SVH
`include "rvv_backend.svh"
`endif
`ifndef RVV_ASSERT__SVH
`include "rvv_backend_sva.svh"
`endif

module rvv_backend_decode_de2
(
  clk, 
  rst_n,
  lcmd_valid,
  lcmd,
  pop,
  push,
  uop,
  uq_ready,
  trap_flush_rvv 
);
//
// interface signals
//
  // global signal
  input   logic                         clk;
  input   logic                         rst_n;
  // signals from command queue
  input   logic   [`NUM_DE_INST-1:0]    lcmd_valid;
  input   LCMD_t  [`NUM_DE_INST-1:0]    lcmd;
  output  logic   [`NUM_DE_INST-1:0]    pop;
  // signals from Uops Quue
  output  logic   [`NUM_DE_UOP-1:0]     push;
  output  UOP_QUEUE_t [`NUM_DE_UOP-1:0] uop;
  input   logic   [`NUM_DE_UOP-1:0]     uq_ready;
  // trap-flush
  input   logic                         trap_flush_rvv;  

//
// internal signals
//
  // the decoded uops
  logic       [`NUM_DE_INST-1:0][`NUM_DE_UOP-1:0] de_uop_valid;
  UOP_QUEUE_t [`NUM_DE_INST-1:0][`NUM_DE_UOP-1:0] de_uop;
  // uop index from controller
  logic       [`UOP_INDEX_WIDTH-1:0]              uop_index_remain;
  // for-loop
  genvar                                          i;

//
// decode
//
  // decode unit
  rvv_backend_decode_unit_de2 u_decode_unit0_de2
  (
    .lcmd_valid             (lcmd_valid[0]),
    .lcmd                   (lcmd[0]),
    .uop_index_remain       (uop_index_remain),
    .uop_valid              (de_uop_valid[0]),
    .uop                    (de_uop[0])
  );

  generate 
    for (i=1;i<`NUM_DE_INST;i=i+1) begin: DECODE_UNIT
      rvv_backend_decode_unit_de2 u_decode_unit_de2
      (
        .lcmd_valid         (lcmd_valid[i]),
        .lcmd               (lcmd[i]),
        .uop_index_remain   ({`UOP_INDEX_WIDTH{1'b0}}),
        .uop_valid          (de_uop_valid[i]),
        .uop                (de_uop[i])
      );    
    end
  endgenerate

  // decode controller
  rvv_backend_decode_ctrl u_decode_ctrl
  (
    .clk                    (clk),
    .rst_n                  (rst_n),
    .de_uop_valid           (de_uop_valid),
    .de_uop                 (de_uop),
    .uop_index_remain       (uop_index_remain),
    .pop                    (pop),
    .push                   (push),
    .uop                    (uop),
    .uq_ready               (uq_ready),
    .trap_flush_rvv         (trap_flush_rvv)
  );

endmodule

