751	    assign lsu_rs_valid_pre = ~lsu_rs_almost_empty;
752	    generate
753	        for (i=0; i<`NUM_LSU; i++) begin: gen_lsu_valid
754	            if (i==0) begin: gen_first
755	                assign uop_lsu_valid_rvv2lsu[i] = lsu_rs_valid_pre[i];
756	            end else begin: gen_i
757	                assign uop_lsu_valid_rvv2lsu[i] = lsu_rs_valid_pre[i] & (uop_lsu_valid_rvv2lsu[i-1] & uop_lsu_ready_lsu2rvv[i-1]);
758	            end
759	        end
760	    endgenerate
761	
762	    // LSU MAP INFO
763	    multi_fifo #(
764	        .T            (LSU_MAP_INFO_t),
765	        .M            (`NUM_DP_UOP),
766	        .N            (`NUM_LSU),
767	        .DEPTH        (`LSU_RS_DEPTH),
768	        .ASYNC_RSTN   (1'b1),
769	        .CHAOS_PUSH   (1'b1)
770	    ) u_lsu_map_info (
771	      // global
772	        .clk          (clk),
773	        .rst_n        (rst_n),
774	      // write
775	        .push         (mapinfo_valid_dp2lsu),
776	        .datain       (mapinfo_dp2lsu),
777	      // read
778	        .pop          (pop_mapinfo),
779	        .dataout      (mapinfo),
780	      // fifo status
781	        .full         (),
782	        .almost_full  (mapinfo_almost_full),
783	        .empty        (mapinfo_empty),
784	        .almost_empty (mapinfo_almost_empty),
785	        .clear        (trap_flush_rvv),
786	        .fifo_data    (),
787	        .wptr         (),
788	        .rptr         (),
789	        .entry_count  ()
790	    );
791	
792	    assign mapinfo_ready_lsu2dp = ~mapinfo_almost_full;
793	
794	  // trap handler
795	    // make sure all lsu uops before the trapping uop have been pushed into LSU_RES_FIFO 
796	    assign trap_en = trap_valid_rvs2rvv & (uop_lsu_valid_lsu2rvv=='b0) & (!lsu_res_almost_full[0]) & (!is_trapping);
797	
798	    cdffr
799	    trap_valid
800	    (
801	      .clk            (clk),
802	      .rst_n          (rst_n),
803	      .e              (trap_en),
804	      .c              (trap_ready_rvv2rvs),
805	      .d              (1'b1),
806	      .q              (is_trapping)
807	    );
808	
809	  // LSU feedback result
810	    assign uop_lsu_valid = trap_en ? 'b1 : uop_lsu_valid_lsu2rvv;
811	    
812	    generate
813	      assign uop_lsu[0].trap_valid = trap_en;
814	      assign uop_lsu[0].uop_lsu2rvv = trap_en ? 'b0 : uop_lsu_lsu2rvv[0];
815	      
816	      for (i=1;i<`NUM_LSU;i++) begin: get_uop_lsu
817	        assign uop_lsu[i].trap_valid = 'b0;
818	        assign uop_lsu[i].uop_lsu2rvv = uop_lsu_lsu2rvv[i];
819	      end
820	    endgenerate
821	
822	    multi_fifo #(
823	        .T            (UOP_LSU_t),
824	        .M            (`NUM_LSU),
825	        .N            (`NUM_LSU),
826	        .DEPTH        (`NUM_LSU*2),
827	        .ASYNC_RSTN   (1'b1),
828	        .CHAOS_PUSH   (1'b1)
829	    ) u_lsu_res (
830	      // global
831	        .clk          (clk),
832	        .rst_n        (rst_n),
833	      // write
834	        .push         (uop_lsu_valid&uop_lsu_ready_rvv2lsu),
835	        .datain       (uop_lsu),
836	      // read
837	        .pop          (pop_lsu_res),
838	        .dataout      (lsu_res),
839	      // fifo status
840	        .full         (),
841	        .almost_full  (lsu_res_almost_full),
842	        .empty        (lsu_res_empty),
843	        .almost_empty (lsu_res_almost_empty),
844	        .clear        (trap_flush_rvv),
845	        .fifo_data    (),
846	        .wptr         (),
847	        .rptr         (),
848	        .entry_count  ()
849	    );
850	    // ready signal for LSU
851	    assign uop_lsu_ready = ~lsu_res_almost_full;
852	    assign uop_lsu_ready_rvv2lsu = is_trapping ? 'b0 : uop_lsu_ready;
853	
854	  // PU, Process unit
855	    // ALU
856	    assign uop_valid_rs2alu = ~fifo_almost_empty_rs2alu;
857	    rvv_backend_alu #(
858	    ) u_alu (
859	      // ALU_RS to ALU
860	        .clk                        (clk),
861	        .rst_n                      (rst_n),
862	        .pop                        (pop_alu2rs),
863	        .uop_valid                  (uop_valid_rs2alu),
864	        .uop                        (uop_rs2alu),
865	      // ALU to ROB  
866	        .result_valid               (res_valid_alu),
867	        .result                     (res_alu),
868	        .result_ready               (res_ready_alu),
869	      // trap-flush
870	        .trap_flush_rvv             (trap_flush_rvv)
871	    );
872	
873	    // PMTRDT
874	    rvv_backend_pmtrdt #(
875	    ) u_pmtrdt (
876	        .clk                        (clk),
877	        .rst_n                      (rst_n),
878	      // PMTRDT_RS to PMTRDT
879	        .pop_ex2rs                  (pop_pmtrdt2rs),
880	        .pmtrdt_uop_rs2ex           (uop_rs2pmtrdt),
881	        .fifo_almost_empty_rs2ex    (fifo_almost_empty_rs2pmtrdt),
882	      // PMT to VRF
883	        .rd_index_pmt2vrf           (rd_index_pmt2vrf),
884	        .rd_data_vrf2pmt            (rd_data_vrf2pmt),
885	      // PMTRDT to ROB
886	        .result_valid_ex2rob        (res_valid_pmtrdt),
887	        .result_ex2rob              (res_pmtrdt),
888	        .result_ready_rob2ex        (res_ready_pmtrdt),
889	      // MISC
890	        .rob_entry_rob2rt           (rob_entry_rob2rt),
891	      // trap-flush
892	        .trap_flush_rvv             (trap_flush_rvv)
893	    );
894	    
895	    // MULMAC
896	    rvv_backend_mulmac #(
897	    ) u_mulmac (
898	        .clk                        (clk),
899	        .rst_n                      (rst_n),
900	        .trap_flush_rvv             (trap_flush_rvv),
901	        .uop_valid_rs2ex            (~fifo_almost_empty_rs2mul),
902	        .mac_uop_rs2ex              (uop_rs2mul),
903	        .pop                        (pop_mul2rs),
904	        .res_valid_ex2rob           (res_valid_mul),
905	        .res_ex2rob                 (res_mul),
906	        .res_ready_rob2ex           (res_ready_mul)
907	    );
908	    
909	    // DIV
910	    assign uop_valid_rs2div = ~fifo_almost_empty_rs2div;
911	    rvv_backend_div u_div
912	    (  
913	      .clk                          (clk),
914	      .rst_n                        (rst_n),
915	      // DIV_RS to DIV
916	      .pop                          (pop_div2rs),
917	      .uop_valid                    (uop_valid_rs2div),
918	      .uop                          (uop_rs2div),
919	      // DIV to ROB
920	      .result_valid                 (res_valid_div),
921	      .result                       (res_div),
922	      .result_ready                 (res_ready_div),
923	      // trap-flush
924	      .trap_flush_rvv               (trap_flush_rvv)
925	    );
926	
927	  `ifdef ZVE32F_ON
928	    // FMA
929	    assign uop_valid_rs2falu = ~fifo_almost_empty_rs2falu;
930	    rvv_backend_falu u_falu
931	    (  
932	      .clk                          (clk),
933	      .rst_n                        (rst_n),
934	      // FMA_RS to FMA
935	      .pop                          (pop_falu2rs),
936	      .uop_valid                    (uop_valid_rs2falu),
937	      .uop                          (uop_rs2falu),
938	      // FMA to ROB
939	      .result_valid                 (res_valid_falu),
940	      .result                       (res_falu),
941	      .result_ready                 (res_ready_falu),
942	      // trap-flush
943	      .trap_flush_rvv               (trap_flush_rvv)
944	    );
945	   `endif
946	
947	    // LSU remap
948	    assign mapinfo_valid = ~mapinfo_almost_empty;
949	    assign lsu_res_valid = ~lsu_res_almost_empty;
950	    rvv_backend_lsu_remap
951	    u_lsu_remap
952	    (
953	      .mapinfo_valid                (mapinfo_valid),
954	      .mapinfo                      (mapinfo),
955	      .pop_mapinfo                  (pop_mapinfo),
956	      .lsu_res_valid                (lsu_res_valid),
957	      .lsu_res                      (lsu_res),
958	      .pop_lsu_res                  (pop_lsu_res),
959	      .result_valid                 (res_valid_lsu),
960	      .result                       (res_lsu),      
961	      .result_ready                 (res_ready_lsu),
962	      .trap_valid_rmp2rob           (trap_valid_rmp2rob),
963	      .trap_rob_entry_rmp2rob       (trap_rob_entry_rmp2rob),
964	      .trap_ready_rob2rmp           (trap_ready_rob2rmp)  
965	    );
966	
967	    assign res_valid_pu2arb = {
968	                              `ifdef ZVE32F_ON
969	                               res_valid_falu,
970	                              `endif
971	                               res_valid_div,
972	                               res_valid_pmtrdt,  
973	                               res_valid_mul,
974	                               res_valid_alu,
975	                               res_valid_lsu
976	                              };
977	                             
978	    assign res_pu2arb = {
979	                        `ifdef ZVE32F_ON
980	                         res_falu,
981	                        `endif
982	                         res_div,
983	                         res_pmtrdt,
984	                         res_mul,
985	                         res_alu,
986	                         res_lsu
987	                        };
988	
