1023	            .almost_empty (),
1024	            .clear        (trap_flush_rvv),
1025	            .fifo_data    (),
1026	            .wptr         (),
1027	            .rptr         (),
1028	            .entry_count  ()
1029	        );
1030	
1031	        assign res_ready_arb2pu[i] = !res_ff_full[i]; 
1032	        assign req_ari[i]          = !res_ff_empty[i];
1033	      end
1034	    endgenerate
1035	
1036	    assign res_ready_arb2pu[`NUM_LSU-1:0] = ~res_valid_lsu | grant_arb[`NUM_LSU-1:0];
1037	
1038	    assign req_arb  = {req_ari,res_valid_lsu};
1039	    assign item_arb = {item_ari, res_lsu};
1040	
1041	    rvv_backend_arb 
1042	    u_arb(
1043	      .clk          (clk),
1044	      .rst_n        (rst_n),
1045	      .req          (req_arb),
1046	      .item         (item_arb),
1047	      .grant        (grant_arb),
1048	      .result_valid (res_valid_arb2rob),
1049	      .result       (res_arb2rob)
1050	    );
1051	
1052	`else
1053	    assign res_valid_arb2rob = res_valid_pu2arb;
1054	    assign res_arb2rob       = res_pu2arb;
1055	    assign res_ready_arb2pu  = '1;
1056	`endif
1057	
1058	  // ROB, Re-Order Buffer
1059	    rvv_backend_rob #(
1060	    ) u_rob (
1061	      // global signal
1062	        .clk                    (clk),
1063	        .rst_n                  (rst_n),
1064	      // Dispatch to ROB
1065	        .uop_valid_dp2rob       (uop_valid_dp2rob),
1066	        .uop_dp2rob             (uop_dp2rob),
1067	        .uop_ready_rob2dp       (uop_ready_rob2dp),
1068	        .rob_empty              (rob_empty),
1069	        .rob_entry_rob2dp       (rob_entry_rob2dp),
1070	      // PU to ROB
1071	        .wr_valid_pu2rob        (res_valid_arb2rob),
1072	        .wr_pu2rob              (res_arb2rob),
1073	      // ROB to RT
1074	        .rd_valid_rob2rt        (rd_valid_rob2rt),
1075	        .rd_rob2rt              (rd_rob2rt),
1076	        .rd_ready_rt2rob        (rd_ready_rt2rob),
1077	        .rob_entry_rob2rt       (rob_entry_rob2rt),
1078	      // ROB to DP
1079	        .uop_rob2dp             (uop_rob2dp),
1080	      // Trap
1081	        .trap_valid_rmp2rob     (trap_valid_rmp2rob),
1082	        .trap_rob_entry_rmp2rob (trap_rob_entry_rmp2rob),
1083	        .trap_ready_rob2rmp     (trap_ready_rob2rmp),
1084	        .trap_ready_rvv2rvs     (trap_ready_rvv2rvs),
1085	        .trap_flush_rvv         (trap_flush_rvv)
1086	    );
